import { defaultReferences, type reference } from "./reference";

export function processTree(root: HTMLElement, supportedReferences?: reference[]): void {
  supportedReferences ??= defaultReferences;

  for (const reference of supportedReferences) {
    const selector = selectorFor(reference);
    for (const el of [...root.querySelectorAll<HTMLElement>(selector)]) {
      resolveReference(el, reference.attribute);
    }
  }
}

function resolveReference(element: HTMLElement, attribute: string): void {
  const query = element.getAttribute(attribute);
  if (!query) {
    return;
  }

  const target = findTarget(element, query);
  if (!target) {
    console.error(`idref ${query} for ${attribute} on ${element.tagName} did not resolve to an element.`);
    return;
  }

  if (!target.id) {
    target.id = `idref--${crypto.randomUUID()}`;
  }

  element.setAttribute(attribute, target.id);
}

function findTarget(source: Element, query: string): Element | null {
  const match = query.match(/^\$(?<verb>find|next|prev|closest)?( (?<selector>.+))?$/i);
  const verb = match?.groups!["verb"];
  const selector = match?.groups!["selector"];

  if (!verb && selector) {
    return document.querySelector<HTMLElement>(selector);
  }

  if (verb === "next") {
    return selector ? applyUntil(source, e => e.nextElementSibling, e => e.matches(selector)) : source.nextElementSibling;
  }

  if (verb === "prev") {
    return selector ? applyUntil(source, e => e.previousElementSibling, e => e.matches(selector)) : source.previousElementSibling;
  }

  if (verb === "closest" && selector) {
    return applyUntil(source, e => e.parentElement, e => e.matches(selector));
  }

  if (verb === "find" && selector) {
    return source.querySelector<HTMLElement>(selector);
  }

  console.error(`Invalid idref-query ${query}.`);
  return null;
}

function applyUntil<T>(start: T, step: (current: T) => T | null, predicate: (current: T) => boolean): T | null {
  let current = step(start);
  while (current) {
    if (predicate(current)) {
      return current;
    }

    current = step(current);
  }

  return null;
}

function selectorFor(ref: reference): string {
  return ref.elements
    ? `:is(${ref.elements.join(", ")})[${ref.attribute}^='$']`
    : `[${ref.attribute}^='$']`;
}
